import React, { useEffect, useCallback } from 'react';
import { View, Text, Linking, StyleSheet, Button, Alert } from 'react-native';
import { NavigationContainer, useNavigation } from '@react-navigation/native';
import { createStackNavigator } from '@react-navigation/stack';

// --- Placeholder Screens ---
function HomeScreen({ navigation }) {
  return (
    <View style={styles.container}>
      <Text style={styles.title}>Welcome Home!</Text>
      <Button title="Go to Profile (Manual)" onPress={() => navigation.navigate('Profile', { id: 'manualUser' })} />
      <Button title="Go to Payment (Manual)" onPress={() => navigation.navigate('PaymentConfirm')} />
      <Text style={styles.subtitle}>Try opening deep links:</Text>
      <Text>myapp://profile/456</Text>
      <Text>myapp://payment/confirm</Text>
    </View>
  );
}

function ProfileScreen({ route }) {
  const { id } = route.params;
  return (
    <View style={styles.container}>
      <Text style={styles.title}>Profile Screen</Text>
      <Text style={styles.subtitle}>User ID: {id}</Text>
    </View>
  );
}

function PaymentConfirmScreen() {
  return (
    <View style={styles.container}>
      <Text style={styles.title}>Payment Confirmation</Text>
      <Text style={styles.subtitle}>Your payment is being processed.</Text>
    </View>
  );
}

const Stack = createStackNavigator();

function AppNavigator() {
  const navigation = useNavigation(); // Get navigation object for use in handleDeepLink

  const handleDeepLink = useCallback((event) => {
    const { url } = event;
    if (!url) {
      return;
    }

    console.log('Received deep link URL:', url);

    const parsedUrl = new URL(url);
    const scheme = parsedUrl.protocol.replace(':', ''); // e.g., 'myapp'
    const host = parsedUrl.hostname; // e.g., 'profile', 'payment'
    const pathSegments = parsedUrl.pathname.split('/').filter(Boolean); // e.g., ['123'], ['confirm']

    if (scheme !== 'myapp') {
      console.log('Unsupported scheme:', scheme);
      return;
    }

    switch (host) {
      case 'profile':
        if (pathSegments.length > 0) {
          const userId = pathSegments[0];
          navigation.navigate('Profile', { id: userId });
          console.log('Navigated to Profile with ID:', userId);
        } else {
          Alert.alert('Deep Link Error', 'Profile link missing user ID.');
        }
        break;
      case 'payment':
        if (pathSegments.length > 0 && pathSegments[0] === 'confirm') {
          navigation.navigate('PaymentConfirm');
          console.log('Navigated to Payment Confirmation.');
        } else {
          Alert.alert('Deep Link Error', 'Payment link not recognized.');
        }
        break;
      default:
        Alert.alert('Deep Link Error', `Unknown host: ${host}`);
        console.log('Unknown deep link host:', host);
    }
  }, [navigation]);

  useEffect(() => {
    // 1. Handle initial deep link when app is launched from a URL
    Linking.getInitialURL().then((url) => {
      if (url) {
        handleDeepLink({ url });
      }
    }).catch(err => console.error('An error occurred getting initial URL', err));

    // 2. Handle deep links when app is already running
    const subscription = Linking.addEventListener('url', handleDeepLink);

    // Clean up the event listener when the component unmounts
    return () => {
      subscription.remove();
    };
  }, [handleDeepLink]);

  return (
    <Stack.Navigator initialRouteName="Home">
      <Stack.Screen name="Home" component={HomeScreen} />
      <Stack.Screen name="Profile" component={ProfileScreen} />
      <Stack.Screen name="PaymentConfirm" component={PaymentConfirmScreen} options={{ title: 'Confirm Payment' }} />
    </Stack.Navigator>
  );
}

export default function App() {
  return (
    <NavigationContainer>
      <AppNavigator />
    </NavigationContainer>
  );
}

